<template>
    <div class="pa-5">
        <v-card>
            <v-card-actions>
                <v-spacer></v-spacer>
                <v-btn small color="primary" @click="subscription_dialog = true">New Subscription</v-btn>
            </v-card-actions>
            <v-data-table
                :headers="headers"
                :items="subscriptions"
                class="elevation-1"
                >
                <template v-slot:body = {items}>
                    <tbody>
                        <tr
                            v-for="item in items"
                            :key="item.id"
                        >
                            <td><v-btn text small @click="$store.state.user.account_type =='admin' ? viewClients(item) : null;">{{ item.user.name }}</v-btn></td>
                            <td><v-btn text small target="_blank" :to="{name : 'Dashboard', params : {code : item.event_code}}">{{ item.event_code }}</v-btn></td>
                            <td>{{ item.start_date }}</td>
                            <td>{{ item.end_date }}</td>
                            <td>
                                <div :style="{background : item.theme, width:'20px', height : '20px', borderRadius : '10px'}"></div>
                            </td>
                            <td>{{ item.hash_tag }}</td>
                            <td class="text-center">
                                <v-btn small icon @click="image = item.background; image_dialog=true;">
                                    <v-icon>mdi-image</v-icon>
                                </v-btn>
                            </td>
                            <td class="text-center">
                                <v-btn small icon @click="image = item.banner; image_dialog=true;">
                                    <v-icon>mdi-image</v-icon>
                                </v-btn>
                            </td>
                            <td class="text-center">
                                <v-btn small icon @click="image = item.logo; image_dialog=true;">
                                    <v-icon>mdi-image</v-icon>
                                </v-btn>
                            </td>
                            <td>{{ item.enable_message_approval == 1 ? 'Yes' : 'No' }}</td>
                            <td>{{ item.show_timestamp == 1 ? 'Yes' : 'No' }}</td>
                            <td>
                                <v-btn x-small color="success" dark block
                                    target="_blank"
                                    class="mb-2"
                                    :to="{name: 'ApprovedTestimonials', params : {id : item.subscription_key}}">
                                    Approved
                                </v-btn>
                                <v-btn x-small color="warning" block
                                    target="_blank"
                                    class="mb-2"
                                    :to="{name: 'PendingTestimonials', params : {id : item.subscription_key}}">
                                    Pending
                                </v-btn>
                                <v-btn x-small color="error" block
                                    target="_blank"
                                    :to="{name: 'RejectedTestimonials', params : {id : item.subscription_key}}">
                                    Rejected
                                </v-btn>
                            </td>
                            <td>
                                <v-btn x-small color="primary" text @click="edit(item)">Edit</v-btn>
                                <v-btn x-small color="error" text>Cancel</v-btn>
                            </td>
                            <td>
                                <v-btn x-small color="primary" @click="details = item; qr_code_dialog = true;">View</v-btn>
                            </td>
                        </tr>
                    </tbody>
                </template>
            </v-data-table>
        </v-card>
        <v-dialog v-model="subscription_dialog" width="500">
            <subscription-dialog :data="subscription" @refresh="refreshData" @close="subscription_dialog = false"/>
        </v-dialog>
        <v-dialog v-model="subscription_edit_dialog" width="500">
            <subscription-edit-dialog :subscription="subscription" @refresh="refreshData" @close="subscription_dialog = false"/>
        </v-dialog>
        <v-dialog v-model="image_dialog" width="500">
            <v-card>
                <img :src="image" alt="" width="100%">
            </v-card>
        </v-dialog>
        <v-dialog v-model="qr_code_dialog" width="300">
            <v-card>
                <v-card-text class="text-center pa-2">
                    <a :href="details.link">{{ details.link }}</a>
                </v-card-text>
                <v-divider></v-divider>
                <img :src="details.qr_code" width="300" >
            </v-card>
        </v-dialog>
        <v-dialog v-model="clients_dialog" width="500">
            <v-card>
                <v-card-title>
                    Link Subscription
                </v-card-title>
                <v-card-text class="pa-2">
                    <v-list dense>
                        <v-list-item v-for="c in clients" :key="c.id" @click="transferToClient(c)">
                            <v-list-item-avatar color="grey darken-4">
                                <span class="text-h5 white--text">{{ c.name.substring(0, 1) }}</span>
                            </v-list-item-avatar>
                            <v-list-item-content>
                                <v-list-item-subtitle>{{ c.name }}</v-list-item-subtitle>
                                <v-list-item-subtitle>{{ c.email }}</v-list-item-subtitle>
                            </v-list-item-content>
                        </v-list-item>
                    </v-list>
                </v-card-text>
                <v-divider></v-divider>
                <img :src="details.qr_code" width="300" >
            </v-card>
        </v-dialog>
    </div>
</template>
<script>
import SubscriptionDialog from '@/views/admin/dialog/SubscriptionDialog.vue';
import SubscriptionEditDialog from '@/views/admin/dialog/SubscriptionEditDialog.vue';
import axios from 'axios';
export default {
    name : 'SubscriptionsView',
    components : {
        SubscriptionDialog,
        SubscriptionEditDialog
    },
    mounted() {
        this.refreshData();
    },
    methods: {
        edit(details) {
            this.subscription = details;
            this.subscription_edit_dialog = true;
        },
        refreshData() {
            axios({
                url : this.$store.state.api_url + '/subscriptions',
                method : 'GET',
                headers : {
                    Authorization : 'Bearer ' + this.$store.state.user.token
                }
            }).then(res => {
                this.subscriptions = res.data;
            });
        },
        viewClients(subscription) {
            this.subscription = subscription;
            this.clients_dialog = true;
            axios({
                url : this.$store.state.api_url + '/admin/clients',
                method : 'GET',
                headers : {
                    Authorization : 'Bearer ' + this.$store.state.user.token
                }
            }).then(res => {
                this.clients = res.data;
            });
        },
        transferToClient(c) {
            axios({
                url : this.$store.state.api_url + '/subscriptions/'+ this.subscription.id +'/transfer',
                method : 'POST',
                data : {'id' : c.id},
                headers : {
                    Authorization : 'Bearer ' + this.$store.state.user.token
                }
            }).then(res => {
                this.clients_dialog = false;
                this.refreshData();
            });
        }
    },
    data() {
        return {
            details : {},
            qr_code_dialog : false,
            subscription_dialog : false,
            subscription_edit_dialog : false,
            image_dialog : false,
            image : null,
            subscriptions : [],
            subscription : {},
            clients_dialog : false,
            clients : [],
            headers : [
                {
                    text : 'Subscriber',
                },
                {
                    text : 'Event Code',
                    value : 'event_code',
                    sortable : true
                },
                {
                    text : 'Start Date',
                    value : 'start_date',
                    sortable : true
                },
                {
                    text : 'End Date',
                    value : 'end_date',
                    sortable : true
                },
                {
                    text : 'Theme',
                    value : 'theme',
                    sortable : false
                },
                {
                    text : 'Hashtag',
                    value : 'hashtag',
                    sortable : true
                },
                {
                    text : 'Background',
                    value : 'background',
                    sortable : false
                },
                {
                    text : 'Banner',
                    value : 'banner',
                    sortable : false
                },
                {
                    text : 'Logo',
                    value : 'logo',
                    sortable : false
                },
                {
                    text : 'Requires Approval',
                    value : 'enable_message_approval'
                },
                {
                    text : 'Display Timestamp',
                    value : 'show_timestamp'
                },
                {
                    text : 'Wall Posts',
                },
                {
                    text : 'Actions',
                },
                {
                    text : 'QR Code',
                }
            ]
        }
    }
}
</script>